// src/components/FormPaciente.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormPaciente({ onNovoPaciente, pacienteEditando, onFimEdicao }) {
  const [numeroProntuario, setNumeroProntuario] = useState(''); // novo estado
  const [nome, setNome] = useState('');
  const [telefone, setTelefone] = useState('');
  const [mensagem, setMensagem] = useState('');

  // Carrega dados quando estiver editando
  useEffect(() => {
    if (pacienteEditando) {
      setNumeroProntuario(pacienteEditando.numero_prontuario || ''); // popula se existir
      setNome(pacienteEditando.nome || '');
      setTelefone(formatarTelefone(pacienteEditando.telefone || ''));
    } else {
      setNumeroProntuario(''); // limpa quando não editar
      setNome('');
      setTelefone('');
    }
    setMensagem('');
  }, [pacienteEditando]);

  // Validações existentes...
  function validarNomeCompleto(valor) {
    const partes = valor.trim().split(/\s+/);
    if (partes.length < 2) return false;
    return partes.every(p => p.length >= 2 && /^[A-Za-zÀ-ÖØ-öø-ÿ]+$/.test(p));
  }

  function formatarTelefone(campo) {
    const digitos = campo.replace(/\D/g, '');
    if (digitos.length <= 2) {
      return digitos.replace(/^(\d{0,2})/, '($1');
    }
    if (digitos.length <= 6) {
      return digitos.replace(/^(\d{2})(\d{0,4})/, '($1) $2');
    }
    return digitos.replace(/^(\d{2})(\d{5})(\d{0,4}).*/, '($1) $2-$3');
  }

  // Handler novo para número do prontuário, só dígitos e até 8 chars
  const handleProntuarioChange = e => {
    const apenasDigitos = e.target.value.replace(/\D/g, '').slice(0, 8);
    setNumeroProntuario(apenasDigitos);
  };

  const handleNomeChange = e => {
    setNome(e.target.value);
  };

  const handleTelefoneChange = e => {
    setTelefone(formatarTelefone(e.target.value));
  };

  const handleSubmit = e => {
    e.preventDefault();
    setMensagem('');

    if (!validarNomeCompleto(nome)) {
      setMensagem('Informe nome e sobrenome, cada um com ao menos 2 letras.');
      return;
    }
    const somenteDigitos = telefone.replace(/\D/g, '');
    if (!(somenteDigitos.length === 10 || somenteDigitos.length === 11)) {
      setMensagem('Telefone inválido. Use 10 ou 11 dígitos.');
      return;
    }

    const dados = {
      nome: nome.trim(),
      telefone: somenteDigitos,
      numero_prontuario: numeroProntuario || null  // inclui o novo campo
    };

    if (pacienteEditando) {
      axios
        .put(`/api/pacientes/${pacienteEditando.id}`, dados)
        .then(() => {
          setMensagem('Paciente atualizado com sucesso!');
          onNovoPaciente();
        })
        .catch(() => {
          setMensagem('Erro ao atualizar paciente.');
        });
    } else {
      axios
        .post('/api/pacientes', dados)
        .then(() => {
          setMensagem('Paciente cadastrado com sucesso!');
          onNovoPaciente();
          setNome('');
          setTelefone('');
          setNumeroProntuario(''); // limpa prontuário no novo cadastro
        })
        .catch(() => {
          setMensagem('Erro ao cadastrar paciente.');
        });
    }
  };

  return (
    <div className="bg-white mx-auto max-w-lg rounded-2xl p-6">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">
          {pacienteEditando ? 'Editar Paciente' : 'Novo Paciente'}
        </h2>

        {/* Novo Campo: Número do Prontuário */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Número do Prontuário
            <input
              className="border rounded px-3 py-2 mt-1 w-32"  // largura fixa p/ até 8 dígitos
              value={numeroProntuario}
              onChange={handleProntuarioChange}
              placeholder="Até 8 dígitos"
              type="text"
              maxLength={8}
            />
          </label>
        </div>

        {/* Campo Nome */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Nome
            <input
              className="w-full border rounded px-3 py-2 mt-1"
              required
              value={nome}
              onChange={handleNomeChange}
              placeholder="Nome e sobrenome"
              type="text"
            />
          </label>
        </div>

        {/* Campo Telefone */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Telefone
            <input
              className="w-full border rounded px-3 py-2 mt-1"
              required
              value={telefone}
              onChange={handleTelefoneChange}
              placeholder="(XX) XXXXX-XXXX"
              type="tel"
            />
          </label>
        </div>

        {/* Botões */}
        <div className="flex flex-col md:flex-row gap-4">
          <button
            type="submit"
            className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold py-2 px-6 rounded-full"
          >
            {pacienteEditando ? 'Atualizar' : 'Cadastrar'}
          </button>
          {pacienteEditando && (
            <button
              type="button"
              className="bg-[#DA3648] text-white hover:bg-[#BC3140] px-4 py-2 rounded-full"
              onClick={onFimEdicao}
            >
              Cancelar
            </button>
          )}
        </div>

        {/* Feedback de sucesso/erro */}
        {mensagem && (
          <p className="mt-4 text-red-600">
            {mensagem}
          </p>
        )}
      </form>
    </div>
  );
}

export default FormPaciente;
